+      const source = processed[j];
+      if (source.type === TokenType.OPEN_PAREN || source.type === TokenType.DELIMITER) {
+        break;
+      }
+      if (source.text === 'FROM') {
+        processed[j] = { ...source, type: TokenType.PIPE_FROM };
+        break;
+      }
+    }
+  }
+  return processed;
